<?php
namespace Canvastack\Canvastack\Library\Constants;

/**
 * Safe HTML Constants
 * 
 * Defines constants and utilities for marking HTML content as safe
 * to prevent double-encoding while maintaining security.
 * 
 * USAGE:
 * ======
 * When a function generates safe HTML (already escaped), mark it with
 * SAFE_HTML_MARKER to indicate it should not be escaped again.
 * 
 * SECURITY:
 * =========
 * Only use this marker for HTML generated by trusted internal functions
 * that already escape user input. Never use for raw user input.
 * 
 * @package    Canvastack\Canvastack\Library\Constants
 * @author     wisnuwidi@canvastack.com
 * @copyright  2026 Canvastack
 * @version    1.0.0
 * @since      31 Mar 2026
 */
class SafeHtml {
	
	/**
	 * Marker prefix untuk menandai HTML yang sudah aman
	 * 
	 * Format: {{CANVASTACK_SAFE_HTML}}[actual_html_content]
	 * 
	 * SECURITY NOTE: Hanya gunakan untuk HTML dari trusted sources
	 * yang sudah meng-escape user input dengan benar.
	 */
	const MARKER = '{{CANVASTACK_SAFE_HTML}}';
	
	/**
	 * Mark HTML content as safe (already escaped)
	 * 
	 * Use this to mark HTML generated by form helpers or other trusted
	 * functions that already escape user input.
	 * 
	 * @param string $html Safe HTML content
	 * @return string Marked safe HTML
	 * 
	 * @example
	 * $checkbox = '<div class="ckbox">...</div>';
	 * return SafeHtml::mark($checkbox);
	 */
	public static function mark($html) {
		if (empty($html)) {
			return '';
		}
		
		// Don't double-mark
		if (self::isMarked($html)) {
			return $html;
		}
		
		return self::MARKER . $html;
	}
	
	/**
	 * Check if content is marked as safe HTML
	 * 
	 * @param string $content Content to check
	 * @return bool True if marked as safe HTML
	 */
	public static function isMarked($content) {
		if (empty($content)) {
			return false;
		}
		
		return str_starts_with($content, self::MARKER);
	}
	
	/**
	 * Remove safe HTML marker and return content
	 * 
	 * @param string $content Marked content
	 * @return string Content without marker
	 */
	public static function unmark($content) {
		if (!self::isMarked($content)) {
			return $content;
		}
		
		return substr($content, strlen(self::MARKER));
	}
	
	/**
	 * Process content: unmark if safe, escape if not
	 * 
	 * This is the main function to use in rendering logic.
	 * 
	 * @param string $content Content to process
	 * @return string Safe content (unmarked or escaped)
	 * 
	 * @example
	 * // Safe HTML - will be unmarked
	 * $safe = SafeHtml::mark('<div>Safe</div>');
	 * echo SafeHtml::process($safe); // <div>Safe</div>
	 * 
	 * // User input - will be escaped
	 * $user = $_POST['name'];
	 * echo SafeHtml::process($user); // Escaped output
	 */
	public static function process($content) {
		if (self::isMarked($content)) {
			return self::unmark($content);
		}
		
		// Not marked - escape for safety
		return htmlspecialchars($content, ENT_QUOTES, 'UTF-8');
	}
	
	/**
	 * Validate that HTML is from trusted source
	 * 
	 * Checks if HTML contains only allowed tags and attributes.
	 * Use this for additional validation before marking as safe.
	 * 
	 * @param string $html HTML to validate
	 * @param array $allowedTags Allowed HTML tags (default: common form elements)
	 * @return bool True if HTML is safe
	 */
	public static function validate($html, $allowedTags = ['div', 'input', 'label', 'select', 'option', 'span', 'i', 'a', 'button', 'table', 'tr', 'td', 'th', 'tbody', 'thead', 'script']) {
		// Check for dangerous patterns
		$dangerousPatterns = [
			'/<script[^>]*>.*?<\/script>/is', // Script tags with content
			'/on\w+\s*=/i',                    // Event handlers
			'/javascript:/i',                  // JavaScript protocol
			'/data:text\/html/i',              // Data URI
		];
		
		foreach ($dangerousPatterns as $pattern) {
			if (preg_match($pattern, $html)) {
				return false;
			}
		}
		
		// Extract all tags
		preg_match_all('/<(\w+)/', $html, $matches);
		$foundTags = array_unique($matches[1]);
		
		// Check if all tags are allowed
		foreach ($foundTags as $tag) {
			if (!in_array(strtolower($tag), $allowedTags)) {
				return false;
			}
		}
		
		return true;
	}
}
